<?php
namespace App\Http\Controllers\Api;
use App\Actions\{CreateMaterialWriteOffAction,DeleteMaterialWriteOffAction,UpdateMaterialWriteOffAction};use App\Http\Requests\MaterialWriteOffRequest;use App\Models\{MaterialWriteOff,Project};use App\Http\Controllers\Controller;
class MaterialWriteOffController extends Controller{public function index(Project $project){$this->authorize('view',$project);return $project->materialWriteOffs()->with('material','tags')->latest('date')->get();} public function store(MaterialWriteOffRequest $r,Project $project,CreateMaterialWriteOffAction $a){$this->authorize('update',$project);return $a->execute($r->validated()+['project_id'=>$project->id]);} public function show(MaterialWriteOff $writeOff){$this->authorize('view',$writeOff);return $writeOff->load('material','tags');} public function update(MaterialWriteOffRequest $r,MaterialWriteOff $writeOff,UpdateMaterialWriteOffAction $a){$this->authorize('update',$writeOff);return $a->execute($writeOff,$r->validated());} public function destroy(MaterialWriteOff $writeOff,DeleteMaterialWriteOffAction $a){$this->authorize('delete',$writeOff);$a->execute($writeOff);return response()->noContent();}}
